SELECT C.company_code , C.company_name , H.hospital_code , H.hospital_name , center.center_code , center.center_name , E.employee_name , R.birth , R.sex , E.employee_code , R.checkuped_at , checkup_result.registered_at , R.reservation_state FROM reservation R JOIN employee_checkup EC ON R.employee_checkup_id = EC.employee_checkup_id AND EC.deleted_at IS NULL JOIN employee E ON EC.user_id = E.user_id AND E.deleted_at IS NULL AND E.myself = 1 JOIN company_checkup CC ON EC.company_checkup_id = CC.company_checkup_id AND CC.deleted_at IS NULL JOIN company C ON CC.company_id = C.company_id AND C.deleted_at IS NULL JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id JOIN checkup_contract_type CCT ON CCST.checkup_contract_type_id = CCT.checkup_contract_type_id LEFT JOIN checkup_result_employee ON EC.employee_checkup_id = checkup_result_employee.employee_checkup_id AND C.company_code = checkup_result_employee.company_code JOIN checkup_result ON checkup_result_employee.checkup_result_id = checkup_result.checkup_result_id JOIN center ON CCT.center_id = center.center_id AND center.deleted_at IS NULL JOIN hospital H ON center.hospital_id = H.hospital_id AND H.deleted_at IS NULL WHERE R.deleted_at IS NULL AND (R.reservation_state = 4 OR R.reservation_state = 2) AND R.checkuped_at >= #{companyCheckupDateBegin} AND R.checkuped_at < DATE_ADD(#{companyCheckupDateEnd}, INTERVAL 1 DAY)
AND C.company_id = #{companyId}
AND CC.checkup_year = #{checkupYear}

SELECT C.company_code , C.company_name , H.hospital_code , H.hospital_name , center.center_code , center.center_name , E.employee_name , R.birth , R.sex , E.employee_code , R.checkuped_at , checkup_result.registered_at , R.reservation_state FROM reservation R JOIN employee_checkup EC ON R.employee_checkup_id = EC.employee_checkup_id AND EC.deleted_at IS NULL JOIN employee E ON EC.user_id = E.user_id AND E.deleted_at IS NULL AND E.myself = 1 JOIN company_checkup CC ON EC.company_checkup_id = CC.company_checkup_id AND CC.deleted_at IS NULL JOIN company C ON CC.company_id = C.company_id AND C.deleted_at IS NULL JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id JOIN checkup_contract_type CCT ON CCST.checkup_contract_type_id = CCT.checkup_contract_type_id LEFT JOIN checkup_result_employee ON EC.employee_checkup_id = checkup_result_employee.employee_checkup_id AND C.company_code = checkup_result_employee.company_code JOIN checkup_result ON checkup_result_employee.checkup_result_id = checkup_result.checkup_result_id JOIN center ON CCT.center_id = center.center_id AND center.deleted_at IS NULL JOIN hospital H ON center.hospital_id = H.hospital_id AND H.deleted_at IS NULL WHERE R.deleted_at IS NULL AND (R.reservation_state = 4 OR R.reservation_state = 2) AND R.checkuped_at >= #{hospitalCheckupDateBegin} AND R.checkuped_at < DATE_ADD(#{hospitalCheckupDateEnd}, INTERVAL 1 DAY)
AND H.hospital_id = #{hospitalId}
AND CC.checkup_year = #{checkupYear}

SELECT C.company_code , C.company_name , hospital_center_view.hospital_code , hospital_center_view.hospital_name , hospital_center_view.center_code , hospital_center_view.center_name , E.employee_name , R.birth , R.sex , E.employee_code , R.checkuped_at , R.desired_at , CRE.registered_at AS employee_registered_at , CRE.review , R.reservation_state , EC.employee_checkup_id , checkup_result.file_name , checkup_result.file_name AS org_filename FROM reservation R JOIN employee_checkup EC ON R.employee_checkup_id = EC.employee_checkup_id AND EC.deleted_at IS NULL JOIN employee E ON EC.user_id = E.user_id AND E.deleted_at IS NULL AND E.myself = 1 JOIN company_checkup CC ON EC.company_checkup_id = CC.company_checkup_id AND CC.deleted_at IS NULL JOIN company C ON CC.company_id = C.company_id AND C.deleted_at IS NULL JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id JOIN checkup_contract_type CCT ON CCST.checkup_contract_type_id = CCT.checkup_contract_type_id LEFT JOIN checkup_result_employee CRE ON EC.employee_checkup_id = CRE.employee_checkup_id AND CRE.deleted_at IS NULL LEFT JOIN checkup_result ON CRE.checkup_result_id = checkup_result.checkup_result_id JOIN hospital_center_view ON hospital_center_view.center_id = CCT.center_id WHERE R.deleted_at IS NULL AND (R.reservation_state = 4 OR R.reservation_state = 2)
AND hospital_center_view.hospital_id = #{hospitalId}
AND C.company_id = #{companyId}
AND CC.checkup_year = #{checkupYear}

# ResultMapper.selectCheckupResultCompany SELECT C.company_name , CC.checkup_year , checkup_result.checkup_result_id , checkup_result_employee.checkup_result_employee_id , checkup_result.registered_at , checkup_result.count , checkup_result.file_name , checkup_result.file_name AS org_filename , hospital.hospital_code , hospital.hospital_name , (CASE WHEN checkup_result_employee.checkup_result_employee_id AND checkup_result_employee.company_code = C.company_code THEN 1 ELSE 0 END) AS checkup_count , (CASE WHEN checkup_result_employee.checkup_result_employee_id AND checkup_result_employee.company_code = C.company_code AND checkup_result_employee.deleted_at IS NULL THEN 1 ELSE 0 END) AS count # , SUM(CASE WHEN checkup_result_employee.checkup_result_employee_id THEN 1 ELSE 0 END) AS checkup_count FROM hospital LEFT JOIN checkup_result ON hospital.hospital_id = checkup_result.hospital_id AND checkup_result.deleted_at IS NULL LEFT JOIN checkup_result_employee ON checkup_result.checkup_result_id = checkup_result_employee.checkup_result_id LEFT JOIN employee_checkup ON checkup_result_employee.employee_checkup_id = employee_checkup.employee_checkup_id JOIN company_checkup CC ON employee_checkup.company_checkup_id = CC.company_checkup_id AND CC.checkup_year = #{checkupYear} AND CC.deleted_at IS NULL LEFT JOIN company C ON CC.company_id = C.company_id AND C.deleted_at IS NULL WHERE hospital.deleted_at IS NULL
AND C.company_id = #{companyId}
GROUP BY checkup_result.checkup_result_id ORDER BY C.company_name, checkup_result.registered_at DESC

