SELECT C.company_name , CC.checkup_year , checkup_result.checkup_result_id , checkup_result.registered_at , checkup_result.count , checkup_result.file_name , checkup_result.file_name AS org_filename , hospital_center_view.hospital_code , hospital_center_view.hospital_name , hospital_center_view.center_code , hospital_center_view.center_name , (CASE WHEN checkup_result_employee.checkup_result_employee_id AND checkup_result_employee.company_code = C.company_code THEN 1 ELSE 0 END) AS checkup_count , (CASE WHEN checkup_result_employee.checkup_result_employee_id AND checkup_result_employee.company_code = C.company_code AND checkup_result_employee.deleted_at IS NULL THEN 1 ELSE 0 END) AS count # , SUM(CASE WHEN checkup_result_employee.checkup_result_employee_id THEN 1 ELSE 0 END) AS checkup_count FROM center_manager_company CMC LEFT JOIN company C ON C.company_id = CMC.company_id AND C.deleted_at IS NULL LEFT JOIN center_manager HM ON HM.user_id = CMC.user_id AND HM.deleted_at IS NULL LEFT JOIN hospital_center_view ON hospital_center_view.center_id = HM.center_id JOIN company_checkup CC ON C.company_id = CC.company_id AND CC.checkup_year = #{checkupYear} LEFT JOIN checkup_result_employee ON C.company_code = checkup_result_employee.company_code AND checkup_result_employee.deleted_at IS NULL LEFT JOIN checkup_result ON checkup_result_employee.checkup_result_id = checkup_result.checkup_result_id AND checkup_result.deleted_at IS NULL WHERE CMC.deleted_at IS NULL
AND C.company_id = #{companyId}
AND HM.user_id = #{userId} GROUP BY checkup_result.checkup_result_id ORDER BY checkup_result.registered_at DESC

SELECT checkup_result.checkup_result_id , checkup_result_employee.checkup_result_employee_id , company.company_code , hospital_center_view.hospital_code , hospital_center_view.center_code , checkup_result_employee.employee_name , checkup_result_employee.birth , checkup_result_employee.sex , checkup_result_employee.employee_code , checkup_result_employee.review , checkup_result_item.checkup_result_item_id , checkup_result_item.item_code , checkup_result_item.result_value FROM checkup_result_employee JOIN checkup_result ON checkup_result_employee.checkup_result_id = checkup_result.checkup_result_id AND checkup_result_employee.deleted_at IS NULL JOIN employee_checkup ON checkup_result_employee.employee_checkup_id = employee_checkup.employee_checkup_id AND employee_checkup.deleted_at IS NULL JOIN reservation ON employee_checkup.employee_checkup_id = reservation.employee_checkup_id JOIN company_checkup ON employee_checkup.company_checkup_id = company_checkup.company_checkup_id AND company_checkup.deleted_at IS NULL JOIN employee ON employee_checkup.user_id = employee.user_id AND employee.deleted_at IS NULL JOIN company ON employee.company_id = company.company_id AND company_checkup.company_id = company.company_id AND company.deleted_at IS NULL JOIN hospital_center_view ON checkup_result_employee.center_id = hospital_center_view.center_id JOIN checkup_result_item ON checkup_result_employee.checkup_result_employee_id = checkup_result_item.checkup_result_employee_id AND checkup_result_item.deleted_at IS NULL WHERE checkup_result_employee.deleted_at IS NULL
AND company.company_id = #{companyId}
AND hospital_center_view.hospital_id = #{hospitalId}
AND company_checkup.checkup_year = #{checkupYear} AND checkup_result.registered_at >= #{resultDateBegin} AND checkup_result.registered_at < DATE_ADD(#{resultDateEnd}, INTERVAL 1 DAY)

SELECT checkup_result.checkup_result_id , checkup_result_employee.checkup_result_employee_id , company.company_code , hospital_center_view.hospital_code , hospital_center_view.center_code , checkup_result_employee.employee_name , checkup_result_employee.birth , checkup_result_employee.sex , checkup_result_employee.employee_code , checkup_result_employee.review , checkup_result_item.checkup_result_item_id , checkup_result_item.item_code , checkup_result_item.result_value FROM checkup_result_employee JOIN checkup_result ON checkup_result_employee.checkup_result_id = checkup_result.checkup_result_id AND checkup_result_employee.deleted_at IS NULL JOIN employee_checkup ON checkup_result_employee.employee_checkup_id = employee_checkup.employee_checkup_id AND employee_checkup.deleted_at IS NULL JOIN reservation ON employee_checkup.employee_checkup_id = reservation.employee_checkup_id JOIN company_checkup ON employee_checkup.company_checkup_id = company_checkup.company_checkup_id AND company_checkup.deleted_at IS NULL JOIN employee ON employee_checkup.user_id = employee.user_id AND employee.deleted_at IS NULL JOIN company ON employee.company_id = company.company_id AND company_checkup.company_id = company.company_id AND company.deleted_at IS NULL JOIN hospital_center_view ON checkup_result_employee.center_id = hospital_center_view.center_id JOIN checkup_result_item ON checkup_result_employee.checkup_result_employee_id = checkup_result_item.checkup_result_employee_id AND checkup_result_item.deleted_at IS NULL WHERE checkup_result_employee.deleted_at IS NULL
AND checkup_result_employee.checkup_result_employee_id = #{checkupResultEmployeeId}
AND company.company_id = #{companyId} AND company_checkup.checkup_year = #{checkupYear}

SELECT checkup_result_employee.checkup_result_employee_id , company.company_code , company.company_name , hospital_center_view.hospital_code , hospital_center_view.hospital_name , hospital_center_view.center_code , hospital_center_view.center_name , checkup_result_employee.employee_name , checkup_result_employee.birth , checkup_result_employee.sex , checkup_result_employee.employee_code , reservation.confirmed_at , reservation.checkuped_at , checkup_result_employee.registered_at AS employee_registered_at FROM checkup_result_employee JOIN hospital_center_view ON hospital_center_view.center_id = checkup_result_employee.center_id JOIN employee_checkup ON checkup_result_employee.employee_checkup_id = employee_checkup.employee_checkup_id AND employee_checkup.deleted_at IS NULL JOIN company_checkup ON employee_checkup.company_checkup_id = company_checkup.company_checkup_id AND company_checkup.checkup_year = #{checkupYear} AND company_checkup.deleted_at IS NULL JOIN company ON company_checkup.company_id = company.company_id AND company.deleted_at IS NULL JOIN reservation ON employee_checkup.employee_checkup_id = reservation.employee_checkup_id AND (reservation.reservation_state != 0 OR reservation.confirmed_at IS NULL) AND reservation.deleted_at IS NULL WHERE checkup_result_employee.deleted_at IS NULL AND company.company_id = #{companyId}
AND hospital_center_view.hospital_id = #{hospitalId}
ORDER BY checkup_result_employee.registered_at DESC

