INSERT INTO checkup_result_employee
( checkup_result_id
, center_id
, employee_checkup_id
, company_code
, employee_code
, employee_name
, birth
, sex
, checkuped_at
, registered_at
, review
, created_user_id
, updated_user_id)
VALUES
( #{checkupResultId}
, (SELECT center_id FROM hospital_center_view WHERE hospital_code = #{hospitalCode}
AND center_code = #{centerCode})
, (SELECT employee_checkup.employee_checkup_id
FROM employee_checkup
JOIN company_checkup ON employee_checkup.company_checkup_id = company_checkup.company_checkup_id
JOIN company ON company_checkup.company_id = company.company_id
JOIN employee ON employee_checkup.user_id = employee.user_id
WHERE company_checkup.checkup_year = #{checkupYear}
AND company.company_code = #{companyCode}
AND employee.employee_code = #{employeeCode}
AND employee.myself = 1)
, #{companyCode}
, #{employeeCode}
, #{employeeNameCrypt}
, #{birth}
, #{sex}
, #{checkupedAt}
, NOW()
, #{review}
, #{sessionUserId}
, #{sessionUserId})

    SELECT LAST_INSERT_ID()

INSERT INTO checkup_result_item
( checkup_result_employee_id
, item_code
, item_category
, item_name
, result_value
, created_user_id
, updated_user_id)
VALUES
    ( #{checkupResultEmployeeId}
    , #{itemCode}
    , #{itemCategory}
    , #{itemName}
    , #{resultValue}
    , #{sessionUserId}
    , #{sessionUserId})
ON DUPLICATE KEY UPDATE item_code       = #{itemCode}
                      , item_category   = #{itemCategory}
                      , item_name       = #{itemName}
                      , result_value    = #{resultValue}
                      , updated_at      = NOW()
                      , updated_user_id = #{sessionUserId}

mapper.update:
UPDATE checkup_result_employee
SET checkup_result_id = #{checkupResultId}
  , review            = #{review}
  , registered_at     = NOW()
  , updated_at        = NOW()
  , updated_user_id   = #{sessionUserId}
  , deleted_at        = NOW()
  , deleted_user_id   = #{sessionUserId}
WHERE employee_checkup_id = #{employeeCheckupId}
  AND employee_code = #{employeeCode}
  AND deleted_at IS NULL

UPDATE checkup_result
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE checkup_result_id = #{checkupResultId}

UPDATE checkup_result_employee
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE deleted_at IS NULL
  AND employee_code = #{employeeCode}
  AND employee_checkup_id = (SELECT employee_checkup.employee_checkup_id
                             FROM employee_checkup
                                          JOIN company_checkup ON employee_checkup.company_checkup_id = company_checkup.company_checkup_id
                                          JOIN company ON company_checkup.company_id = company.company_id
                                          JOIN employee ON employee_checkup.user_id = employee.user_id
                             WHERE company_checkup.checkup_year = #{checkupYear}
                               AND company.company_code = #{companyCode}
                               AND employee.employee_code = #{employeeCode}
                               AND employee.myself = 1)

UPDATE checkup_result_employee
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE checkup_result_id = #{checkupResultId}

UPDATE checkup_result_employee
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE deleted_at IS NULL
  AND checkup_result_employee_id = #{checkupResultEmployeeId}
